import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a Roth IRA?", a: "A Roth IRA is an individual retirement account funded with after-tax dollars. Qualified retirement withdrawals can be tax-free." },
  { q: "What are the Roth IRA contribution limits?", a: "Contribution limits can change by year and may include catch-up amounts for older savers. Always verify the current IRS limit." },
  { q: "What is the difference between Roth and traditional IRA?", a: "Roth IRA contributions are after-tax and qualified withdrawals may be tax-free. Traditional IRA contributions may be deductible, but withdrawals are generally taxable." },
  { q: "Who can contribute to a Roth IRA?", a: "Eligibility depends on earned income and IRS income phaseout rules for the tax year." },
  { q: "Can you withdraw from a Roth IRA early?", a: "Contributions can often be withdrawn anytime, but earnings may face tax or penalties unless rules are met." },
];

const money = (v: number, d = 0) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function fv(balance: number, yearly: number, rate: number, years: number) {
  let value = balance;
  for (let i = 0; i < years; i++) value = value * (1 + rate / 100) + yearly;
  return value;
}

export default function RothIRACalculator() {
  useCurrencyVersion();
  const [age, setAge] = useState(30);
  const [retirementAge, setRetirementAge] = useState(65);
  const [balance, setBalance] = useState(15000);
  const [contribution, setContribution] = useState(6000);
  const [rate, setRate] = useState(7);
  const years = Math.max(0, retirementAge - age);
  const result = useMemo(() => {
    const finalBalance = fv(balance, contribution, rate, years);
    const totalContributions = balance + contribution * years;
    const earnings = finalBalance - totalContributions;
    const monthlyIncome = finalBalance * 0.04 / 12;
    const rows = Array.from({ length: Math.min(years, 60) }, (_, i) => {
      const year = i + 1;
      return { age: age + year, balance: fv(balance, contribution, rate, year), contributions: balance + contribution * year };
    });
    return { finalBalance, totalContributions, earnings, monthlyIncome, rows };
  }, [age, balance, contribution, rate, years]);
  const comparison = [25, 30, 35, 40, 45].map((startAge) => {
    const roth = fv(0, 6000, 7, 65 - startAge);
    const traditional = roth;
    const tax = traditional * 0.22;
    return { startAge, roth, traditional, advantage: tax, tax };
  });

  return (
    <>
      <SEOHead title="Free Roth IRA Calculator Online - Calculate Roth IRA Growth and Tax-Free Retirement Income | CalcHive" description="Free online Roth IRA calculator. Calculate Roth IRA balance at retirement, total tax-free earnings and monthly income with comparison to traditional IRA instantly. 100% free, no signup required." canonical="/roth-ira-calculator" keywords="free roth IRA calculator, roth IRA growth calculator free online, roth vs traditional IRA calculator free, calculate roth IRA returns free, tax free retirement calculator free" category="Financial Calculators" breadcrumbName="Free Roth IRA Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Roth IRA Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate Roth IRA growth, tax-free earnings, and retirement income.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Current age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Retirement age</label><input type="number" value={retirementAge} onChange={(e) => setRetirementAge(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Current Roth IRA balance</label><input type="number" value={balance} onChange={(e) => setBalance(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Annual contribution</label><input type="number" value={contribution} onChange={(e) => setContribution(Number(e.target.value))} className={inputClass} /></div>
            <div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Expected return (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Roth IRA Balance at Retirement</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.finalBalance)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Tax-free earnings</p><p className="text-lg font-extrabold text-foreground">{money(result.earnings)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Monthly income</p><p className="text-lg font-extrabold text-foreground">{money(result.monthlyIncome)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total contributions</p><p className="text-lg font-extrabold text-foreground">{money(result.totalContributions)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Roth IRA Growth and Tax-Free Income for Free</h2><p className="text-muted-foreground leading-relaxed">This Roth IRA growth calculator compounds your current balance and annual contributions until retirement, then estimates monthly income using a 4% withdrawal rate.</p>
          <h2 className="text-2xl font-bold text-foreground">Roth IRA vs Traditional IRA - Which Is Better for You</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Roth IRA vs Traditional IRA - $6,000/year at 7% Return</caption><thead className="bg-muted/60"><tr>{["Starting Age", "Roth Balance at 65", "Traditional Balance at 65", "Roth After-Tax Advantage", "Traditional Tax Owed"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.startAge}><td className="py-2.5 px-3 font-semibold">{row.startAge}</td><td className="py-2.5 px-3">{money(row.roth)}</td><td className="py-2.5 px-3">{money(row.traditional)}</td><td className="py-2.5 px-3">{money(row.advantage)}</td><td className="py-2.5 px-3">{money(row.tax)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Roth IRA Retirement Planning Tool for Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Growth Table</caption><thead className="bg-muted/60"><tr>{["Age", "Contributions", "Projected Balance", "Earnings"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.rows.map((row) => <tr key={row.age}><td className="py-2.5 px-3">{row.age}</td><td className="py-2.5 px-3">{money(row.contributions)}</td><td className="py-2.5 px-3">{money(row.balance)}</td><td className="py-2.5 px-3">{money(row.balance - row.contributions)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/roth-ira-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


